Olha esse service e me diz se está bom:

```typescript
class ReportService {
  async generateMonthlyReport(month: number, year: number) {
    const orders = await db.query('SELECT * FROM orders WHERE EXTRACT(MONTH FROM created_at) = $1 AND EXTRACT(YEAR FROM created_at) = $2', [month, year]);
    let totalRevenue = 0;
    let totalOrders = 0;
    let productCounts: any = {};
    for (const order of orders) {
      totalRevenue += order.total;
      totalOrders++;
      const items = await db.query('SELECT * FROM order_items WHERE order_id = $1', [order.id]);
      for (const item of items) {
        if (productCounts[item.product_id]) {
          productCounts[item.product_id] += item.quantity;
        } else {
          productCounts[item.product_id] = item.quantity;
        }
      }
    }
    const avgOrderValue = totalRevenue / totalOrders;
    const topProducts = Object.entries(productCounts).sort((a: any, b: any) => b[1] - a[1]).slice(0, 10);
    const pdf = new PDFDocument();
    pdf.text('Monthly Report');
    pdf.text('Revenue: ' + totalRevenue);
    pdf.text('Orders: ' + totalOrders);
    pdf.text('AOV: ' + avgOrderValue);
    pdf.text('Top Products: ' + JSON.stringify(topProducts));
    await sendEmail('admin@company.com', 'Monthly Report', pdf);
    return { totalRevenue, totalOrders, avgOrderValue, topProducts };
  }
}
```

